import { MinPriorityQueue } from '@datastructures-js/priority-queue';

function solve(n, edges) {
    const graph = new Map();
    for (const [u, v, start, end] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u).push([v, start, end]);
    }

    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;
    const pq = new MinPriorityQueue({ priority: (node) => node.time });
    pq.enqueue({ time: 0, node: 0 });

    while (!pq.isEmpty()) {
        const { time, node } = pq.dequeue().element;

        if (node === n - 1) {
            return time;
        }

        if (time > dist[node]) {
            continue;
        }

        // Option to wait (stay at current node)
        if (time + 1 < dist[node]) {
            dist[node] = time + 1;
            pq.enqueue({ time: time + 1, node });
        }

        // Check all outgoing edges
        if (graph.has(node)) {
            for (const [v, start, end] of graph.get(node)) {
                if (time > end) {
                    continue;
                }

                const arrivalTime = Math.max(time, start) + 1;
                if (arrivalTime < dist[v]) {
                    dist[v] = arrivalTime;
                    pq.enqueue({ time: arrivalTime, node: v });
                }
            }
        }
    }

    return -1;
}
